mapper.insert:
	/* www.api.mba.auth.Auth.insertJoin */
		INSERT INTO
		MEMBER
		(
            ID
			,PASSWORD
			,NAME
			,EMAIL
			,PHONE
			,TYPE
			,GRADE
			,CREATE_USER
			,CREATE_DATE
			,UPDATE_USER
			,UPDATE_DATE

		)
		VALUES
		(
			#{id}
			,#{password}
			,#{name}
			,#{email}
			,#{phone}
			,#{type}
			,#{grade}
			,#{createUser}
			,now()
			,#{updateUser}
			,now()

		)

	/* www.api.mba.auth.Auth.insertMember */
		INSERT INTO
		MEMBER
		(
            ID
			,PASSWORD
			,NAME
			,EMAIL
			,PHONE
			,TYPE
			,GRADE
			,CREATE_USER
			,CREATE_DATE
			,UPDATE_USER
			,UPDATE_DATE

		)
		VALUES
		(
			#{id}
			,#{password}
			,#{name}
			,#{email}
			,#{phone}
			,#{type}
			,#{grade}
			,#{createUser}
			,now()
			,#{updateUser}
			,now()

		)

mapper.select:
    /* www.api.mba.auth.Auth.selectLogin */
		SELECT ID
		      ,PASSWORD
        FROM MEMBER
        WHERE ID = #{id}
        AND PASSWORD = #{password}
